import { performance } from 'node:perf_hooks';

import {
  MAHA_ANCHOR,
  resolveMahaPhysicalStationRange,
  resolveMahaShardRoute,
} from '../src/amplituhedron-sharding';

const ITERATIONS = Number(process.env['GNOSIS_MAHA_BENCH_ITERATIONS'] ?? 10000);
const WARMUP = Number(process.env['GNOSIS_MAHA_BENCH_WARMUP'] ?? 1000);
const STATION_COUNTS = (process.env['GNOSIS_MAHA_BENCH_STATIONS'] ?? '1,2,3,7,21,42')
  .split(',')
  .map((value) => Number(value.trim()))
  .filter((value) => Number.isInteger(value) && value > 0);
const HASH_STRINGS = Array.from({ length: Math.max(ITERATIONS, WARMUP) }, (_, i) =>
  (18446744073709551615n - BigInt(i)).toString(),
);

interface BenchStation {
  replays: number;
  captures: number;
}

interface BenchResult {
  meanUs: number;
  p50Us: number;
  p95Us: number;
}

function percentile(sorted: readonly number[], q: number): number {
  return sorted[Math.min(sorted.length - 1, Math.floor(sorted.length * q))] ?? 0;
}

function measure(label: string, fn: (i: number) => void): BenchResult {
  for (let i = 0; i < WARMUP; i++) fn(i);

  const samples: number[] = [];
  for (let i = 0; i < ITERATIONS; i++) {
    const t0 = performance.now();
    fn(i);
    samples.push((performance.now() - t0) * 1000);
  }
  samples.sort((a, b) => a - b);
  const meanUs = samples.reduce((sum, value) => sum + value, 0) / samples.length;
  const p50Us = percentile(samples, 0.5);
  const p95Us = percentile(samples, 0.95);

  console.log(
    `${label.padEnd(28)} mean=${meanUs.toFixed(3)}us p50=${p50Us.toFixed(3)}us p95=${p95Us.toFixed(3)}us`,
  );
  return { meanUs, p50Us, p95Us };
}

async function measureAsync(label: string, fn: (i: number) => Promise<void>): Promise<BenchResult> {
  for (let i = 0; i < WARMUP; i++) await fn(i);

  const samples: number[] = [];
  for (let i = 0; i < ITERATIONS; i++) {
    const t0 = performance.now();
    await fn(i);
    samples.push((performance.now() - t0) * 1000);
  }
  samples.sort((a, b) => a - b);
  const meanUs = samples.reduce((sum, value) => sum + value, 0) / samples.length;
  const p50Us = percentile(samples, 0.5);
  const p95Us = percentile(samples, 0.95);

  console.log(
    `${label.padEnd(28)} mean=${meanUs.toFixed(3)}us p50=${p50Us.toFixed(3)}us p95=${p95Us.toFixed(3)}us`,
  );
  return { meanUs, p50Us, p95Us };
}

function makeStations(count: number): BenchStation[] {
  return Array.from({ length: count }, () => ({
    replays: 0,
    captures: 0,
  }));
}

function resetStations(stations: BenchStation[]): void {
  for (const station of stations) {
    station.replays = 0;
    station.captures = 0;
  }
}

function fullFanout(stations: BenchStation[]): void {
  for (const station of stations) station.replays++;
  for (const station of stations) station.captures++;
}

function mahaRouteFanout(stations: BenchStation[], prefixHash: bigint): void {
  const route = resolveMahaShardRoute(stations.length, prefixHash);
  if (!route) return;
  for (let stationIndex = route.start; stationIndex < route.end; stationIndex++) {
    stations[stationIndex]!.replays++;
  }
  for (let stationIndex = route.start; stationIndex < route.end; stationIndex++) {
    stations[stationIndex]!.captures++;
  }
}

function mahaRouteFanoutString(stations: BenchStation[], prefixHash: string): void {
  const route = resolveMahaShardRoute(stations.length, prefixHash);
  if (!route) return;
  for (let stationIndex = route.start; stationIndex < route.end; stationIndex++) {
    stations[stationIndex]!.replays++;
  }
  for (let stationIndex = route.start; stationIndex < route.end; stationIndex++) {
    stations[stationIndex]!.captures++;
  }
}

async function replayStation(station: BenchStation): Promise<void> {
  station.replays++;
}

async function captureStation(station: BenchStation): Promise<void> {
  station.captures++;
}

async function fullAsyncFanout(stations: BenchStation[]): Promise<void> {
  await Promise.all(stations.map((station) => replayStation(station)));
  await Promise.all(stations.map((station) => captureStation(station)));
}

async function mahaAsyncFanout(stations: BenchStation[], prefixHash: bigint): Promise<void> {
  const route = resolveMahaShardRoute(stations.length, prefixHash);
  if (!route) return;

  const replayPromises: Promise<void>[] = [];
  for (let stationIndex = route.start; stationIndex < route.end; stationIndex++) {
    replayPromises.push(replayStation(stations[stationIndex]!));
  }
  await Promise.all(replayPromises);

  const capturePromises: Promise<void>[] = [];
  for (let stationIndex = route.start; stationIndex < route.end; stationIndex++) {
    capturePromises.push(captureStation(stations[stationIndex]!));
  }
  await Promise.all(capturePromises);
}

function routeOnly(count: number, prefixHash: bigint): void {
  const route = resolveMahaShardRoute(count, prefixHash);
  if (!route) throw new Error(`route missing for station count ${count}`);
}

function routeOnlyString(count: number, prefixHash: string): void {
  const route = resolveMahaShardRoute(count, prefixHash);
  if (!route) throw new Error(`route missing for station count ${count}`);
}

function routeOnlyStringBigIntBaseline(count: number, prefixHash: string): void {
  const shard = Number(BigInt(prefixHash) % BigInt(MAHA_ANCHOR));
  const start = Math.floor((shard * count) / MAHA_ANCHOR);
  const end = Math.max(start + 1, Math.floor(((shard + 1) * count) / MAHA_ANCHOR));
  if (end <= start) throw new Error(`route missing for station count ${count}`);
}

function assertCoverage(count: number): void {
  const ranges = Array.from({ length: count }, (_, stationIndex) =>
    resolveMahaPhysicalStationRange(count, stationIndex),
  );
  if (ranges.some((range) => range === null)) {
    throw new Error(`invalid station range for count ${count}`);
  }
  const covered = new Set<number>();
  for (const range of ranges) {
    for (let shard = range!.shardStart; shard < range!.shardEnd; shard++) {
      covered.add(shard);
    }
  }
  if (covered.size !== MAHA_ANCHOR) {
    throw new Error(`expected ${MAHA_ANCHOR} covered shards, got ${covered.size}`);
  }
}

async function main(): Promise<void> {
  console.log(
    `amplituhedron Maha sharding bench iterations=${ITERATIONS} warmup=${WARMUP} virtual_shards=${MAHA_ANCHOR}`,
  );

  for (const count of STATION_COUNTS) {
    assertCoverage(count);
    const stations = makeStations(count);
    console.log(`\nstations=${count}`);

    const route = measure('route-only', (i) => {
      routeOnly(count, BigInt(i));
    });

    const routeString = measure('route-only string', (i) => {
      routeOnlyString(count, HASH_STRINGS[i % HASH_STRINGS.length]!);
    });

    const routeStringBigInt = measure('route-only string BigInt', (i) => {
      routeOnlyStringBigIntBaseline(count, HASH_STRINGS[i % HASH_STRINGS.length]!);
    });

    resetStations(stations);
    const full = measure('full-fanout replay+capture', () => {
      fullFanout(stations);
    });

    resetStations(stations);
    const maha = measure('maha-route replay+capture', (i) => {
      mahaRouteFanout(stations, BigInt(i));
    });

    resetStations(stations);
    const mahaString = measure('maha-route string', (i) => {
      mahaRouteFanoutString(stations, HASH_STRINGS[i % HASH_STRINGS.length]!);
    });

    resetStations(stations);
    const fullAsync = await measureAsync('async full Promise.all', async () => {
      await fullAsyncFanout(stations);
    });

    resetStations(stations);
    const mahaAsync = await measureAsync('async maha Promise.all', async (i) => {
      await mahaAsyncFanout(stations, BigInt(i));
    });

    const touchedFull = count * 2;
    const touchedMaha = (() => {
      const sample = makeStations(count);
      mahaRouteFanout(sample, 5n);
      return sample.reduce((sum, station) => sum + station.replays + station.captures, 0);
    })();

    console.log(
      `touches full=${String(touchedFull).padStart(3)} maha=${String(touchedMaha).padStart(3)} ` +
        `touch_reduction=${(touchedFull / touchedMaha).toFixed(2)}x ` +
        `mean_speedup=${(full.meanUs / maha.meanUs).toFixed(2)}x ` +
        `string_speedup=${(full.meanUs / mahaString.meanUs).toFixed(2)}x ` +
        `async_speedup=${(fullAsync.meanUs / mahaAsync.meanUs).toFixed(2)}x ` +
        `route_tax=${route.meanUs.toFixed(3)}us ` +
        `string_route_tax=${routeString.meanUs.toFixed(3)}us ` +
        `string_bigint_tax=${routeStringBigInt.meanUs.toFixed(3)}us`,
    );
  }
}

await main();
